class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False
        cnt = [0] * 26
        for sc, tc in zip(s, t):
            delta = (ord(tc) - ord(sc)) % 26
            if delta != 0:
                cnt[delta] += 1
        for d in range(1, 26):
            if cnt[d] == 0:
                continue
            max_m = (k - d) // 26
            available = max_m + 1 if max_m >= 0 else 0
            if cnt[d] > available:
                return False
        return True

